content:
{
  "sentences": [
    {
      "text": "請問洗手間在電梯的旁邊嗎？",
      "pinyin": "Qǐngwèn xǐshǒujiān zài diàntī de pángbiān ma?",
      "pinyin_numeric": "qing3wen4 xi3shou3jian1 zai4 dian4ti1 de0 pang2bian1 ma0",
      "translation_en": "Excuse me, is the restroom next to the elevator?",
      "translation_ko": "실례합니다, 화장실이 엘리베이터 옆에 있나요?"
    },
    {
      "text": "出口在櫃台的前面，左轉就可以看到。",
      "pinyin": "Chūkǒu zài guìtái de qiánmiàn, zuǒzhuǎn jiù kěyǐ kàndào.",
      "pinyin_numeric": "chu1kou3 zai4 gui4tai2 de0 qian2mian4, zuo3zhuan3 jiu4 ke3yi3 kan4dao4.",
      "translation_en": "The exit is in front of the counter; turn left and you'll see it.",
      "translation_ko": "출구는 카운터 앞에 있고, 왼쪽으로 돌면 보입니다."
    },
    {
      "text": "教室在二樓樓梯的右邊，不要走錯了。",
      "pinyin": "Jiàoshì zài èr lóu lóutī de yòubiān, bùyào zǒu cuò le.",
      "pinyin_numeric": "jiao4shi4 zai4 er4 lou2 lou2ti1 de0 you4bian1, bu2yao4 zou3 cuo4 le0.",
      "translation_en": "The classroom is on the second floor to the right of the stairs; don't go the wrong way.",
      "translation_ko": "교실은 2층 계단 오른쪽에 있으니 잘못 가지 마세요."
    },
    {
      "text": "服務台在入口的對面，靠近大門。",
      "pinyin": "Fúwùtái zài rùkǒu de duìmiàn, kàojìn dàmén.",
      "pinyin_numeric": "fu2wu4tai2 zai4 ru4kou3 de0 dui4mian4, kao4jin4 da4men2.",
      "translation_en": "The service counter is opposite the entrance, near the main door.",
      "translation_ko": "서비스 데스크는 입구 맞은편, 정문 근처에 있습니다."
    },
    {
      "text": "電梯在一樓走廊的中間，左邊是洗手間。",
      "pinyin": "Diàntī zài yī lóu zǒuláng de zhōngjiān, zuǒbiān shì xǐshǒujiān.",
      "pinyin_numeric": "dian4ti1 zai4 yi1 lou2 zou3lang2 de0 zhong1jian1, zuo3bian1 shi4 xi3shou3jian1.",
      "translation_en": "The elevator is in the middle of the first-floor hallway, with the restroom on the left.",
      "translation_ko": "엘리베이터는 1층 복도 중간에 있고, 왼쪽이 화장실입니다."
    },
    {
      "text": "從這裡到辦公室，要先直走，然後在樓梯的旁邊右轉。",
      "pinyin": "Cóng zhèlǐ dào bàngōngshì, yào xiān zhízǒu, ránhòu zài lóutī de pángbiān yòuzhuǎn.",
      "pinyin_numeric": "cong2 zhe4li3 dao4 ban4gong1shi4, yao4 xian1 zhi2zou3, ran2hou4 zai4 lou2ti1 de0 pang2bian1 you4zhuan3.",
      "translation_en": "To get from here to the office, first go straight, then turn right next to the stairs.",
      "translation_ko": "여기에서 사무실까지 가려면 먼저 직진한 후 계단 옆에서 우회전하세요."
    },
    {
      "text": "請問櫃台在服務台的後面嗎？",
      "pinyin": "Qǐngwèn guìtái zài fúwùtái de hòumiàn ma?",
      "pinyin_numeric": "qing3wen4 gui4tai2 zai4 fu2wu4tai2 de0 hou4mian4 ma0",
      "translation_en": "Excuse me, is the counter behind the service desk?",
      "translation_ko": "실례합니다, 카운터가 서비스 데스크 뒤에 있나요?"
    },
    {
      "text": "教室在三樓，從電梯上去，左邊就是出口。",
      "pinyin": "Jiàoshì zài sān lóu, cóng diàntī shàngqù, zuǒbiān jiù shì chūkǒu.",
      "pinyin_numeric": "jiao4shi4 zai4 san1 lou2, cong2 dian4ti1 shang4qu4, zuo3bian1 jiu4 shi4 chu1kou3.",
      "translation_en": "The classroom is on the third floor; go up by elevator, and the exit is on the left.",
      "translation_ko": "교실은 3층에 있고, 엘리베이터로 올라가면 왼쪽이 출구입니다."
    },
    {
      "text": "洗手間在走廊的後面，靠近樓梯。",
      "pinyin": "Xǐshǒujiān zài zǒuláng de hòumiàn, kàojìn lóutī.",
      "pinyin_numeric": "xi3shou3jian1 zai4 zou3lang2 de0 hou4mian4, kao4jin4 lou2ti1.",
      "translation_en": "The restroom is at the back of the hallway, near the stairs.",
      "translation_ko": "화장실은 복도 뒤쪽, 계단 근처에 있습니다."
    },
    {
      "text": "從入口直走，到櫃台前面左轉，就可以看到電梯。",
      "pinyin": "Cóng rùkǒu zhízǒu, dào guìtái qiánmiàn zuǒzhuǎn, jiù kěyǐ kàndào diàntī.",
      "pinyin_numeric": "cong2 ru4kou3 zhi2zou3, dao4 gui4tai2 qian2mian4 zuo3zhuan3, jiu4 ke3yi3 kan4dao4 dian4ti1.",
      "translation_en": "Go straight from the entrance, turn left in front of the counter, and you'll see the elevator.",
      "translation_ko": "입구에서 직진하여 카운터 앞에서 좌회전하면 엘리베이터가 보입니다."
    }
  ]
}
